const AgentResearcher = () => {
  const [query, setQuery] = React.useState('');
  const [reports, setReports] = React.useState([
    { id: 1, query: 'Market trends in AI 2024', summary: 'AI market projected to reach $1.8T by 2030. Key drivers: generative AI, autonomous agents, and edge computing.', sources: 12, date: '2024-01-15' },
    { id: 2, query: 'Competitor analysis: Tesla vs BYD', summary: 'BYD overtook Tesla in Q4 2023 EV sales. Tesla leads in premium segment and charging infrastructure.', sources: 8, date: '2024-01-10' }
  ]);
  const [loading, setLoading] = React.useState(false);
  const [selected, setSelected] = React.useState(null);

  const runResearch = () => {
    if (!query.trim()) return;
    setLoading(true);
    setTimeout(() => {
      setReports([{
        id: Date.now(),
        query: query,
        summary: 'Research complete. Key findings indicate significant developments in the queried domain. Recommend follow-up analysis on sub-topics.',
        sources: Math.floor(Math.random() * 15) + 3,
        date: new Date().toISOString().slice(0, 10)
      }, ...reports]);
      setLoading(false);
      setQuery('');
    }, 2000);
  };

  return React.createElement('div', { style: { fontFamily: 'system-ui, sans-serif', padding: '16px', display: 'flex', flexDirection: 'column', gap: '16px', height: '100%', overflow: 'auto' } },
    React.createElement('h3', { style: { margin: 0, fontSize: '16px', fontWeight: 600, color: '#111827' } }, 'Research Agent'),
    React.createElement('div', { style: { display: 'flex', gap: '8px' } },
      React.createElement('input', {
        value: query,
        onChange: e => setQuery(e.target.value),
        onKeyDown: e => e.key === 'Enter' && runResearch(),
        placeholder: 'Enter research query...',
        style: { flex: 1, fontSize: '13px', padding: '8px 12px', borderRadius: '6px', border: '1px solid #d1d5db', outline: 'none' }
      }),
      React.createElement('button', {
        onClick: runResearch,
        disabled: loading,
        style: {
          fontSize: '13px',
          padding: '8px 16px',
          borderRadius: '6px',
          border: 'none',
          background: loading ? '#9ca3af' : '#2563eb',
          color: '#fff',
          cursor: loading ? 'not-allowed' : 'pointer',
          fontWeight: 600
        }
      }, loading ? 'Researching...' : 'Research')
    ),
    React.createElement('div', { style: { display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px', flex: 1, minHeight: 0 } },
      React.createElement('div', { style: { background: '#f9fafb', borderRadius: '8px', padding: '12px', display: 'flex', flexDirection: 'column', gap: '8px', overflow: 'auto' } },
        React.createElement('div', { style: { fontSize: '12px', fontWeight: 600, color: '#6b7280', marginBottom: '4px', textTransform: 'uppercase', letterSpacing: '0.05em' } }, 'Recent Reports'),
        reports.map(r => React.createElement('div', {
          key: r.id,
          onClick: () => setSelected(r),
          style: {
            background: selected?.id === r.id ? '#e0e7ff' : '#fff',
            borderRadius: '6px',
            padding: '10px',
            border: selected?.id === r.id ? '1px solid #6366f1' : '1px solid #e5e7eb',
            cursor: 'pointer'
          }
        },
          React.createElement('div', { style: { fontWeight: 600, fontSize: '13px', color: '#111827', marginBottom: '4px' } }, r.query),
          React.createElement('div', { style: { display: 'flex', justifyContent: 'space-between', alignItems: 'center' } },
            React.createElement('span', { style: { fontSize: '11px', color: '#6b7280' } }, r.sources, ' sources'),
            React.createElement('span', { style: { fontSize: '11px', color: '#9ca3af' } }, r.date)
          )
        ))
      ),
      React.createElement('div', { style: { background: '#f9fafb', borderRadius: '8px', padding: '12px', display: 'flex', flexDirection: 'column', gap: '8px' } },
        React.createElement('div', { style: { fontSize: '12px', fontWeight: 600, color: '#6b7280', textTransform: 'uppercase', letterSpacing: '0.05em' } }, 'Report Details'),
        selected ? React.createElement(React.Fragment, null,
          React.createElement('div', { style: { background: '#fff', borderRadius: '6px', padding: '12px', border: '1px solid #e5e7eb', flex: 1 } },
            React.createElement('div', { style: { fontWeight: 600, fontSize: '14px', color: '#111827', marginBottom: '8px' } }, selected.query),
            React.createElement('div', { style: { fontSize: '13px', color: '#374151', lineHeight: 1.6, marginBottom: '12px' } }, selected.summary),
            React.createElement('div', { style: { display: 'flex', gap: '12px' } },
              React.createElement('span', { style: { fontSize: '11px', color: '#6b7280', background: '#f3f4f6', padding: '4px 8px', borderRadius: '4px' } }, selected.sources, ' sources'),
              React.createElement('span', { style: { fontSize: '11px', color: '#6b7280', background: '#f3f4f6', padding: '4px 8px', borderRadius: '4px' } }, selected.date)
            )
          )
        ) : React.createElement('div', { style: { color: '#9ca3af', fontSize: '13px', textAlign: 'center', padding: '20px' } }, 'Select a report to view details')
      )
    )
  );
};
render(<AgentResearcher/>);
